diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index d1eb84b5ca5c..e4d998034331 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4068,7 +4068,16 @@ Instruction *InstCombinerImpl::foldICmpIntrinsicWithConstant(ICmpInst &Cmp,
             Pred, cast<SaturatingInst>(II), C, Builder))
       return Folded;
     break;
+  
   case Intrinsic::ctpop: {
+    // Avoid folding ctpop-based pow2 tests when ctpop has range metadata
+    // excluding 0, as this may introduce poison by assuming ctpop>=1
+    // without respecting guarding conditions (e.g., x != 0).
+    if (II->getMetadata(LLVMContext::MD_range)) {
+      if ((Pred == ICmpInst::ICMP_ULT && C == 2) ||
+          (Cmp.isEquality() && C == 1))
+        break;
+    }
     const SimplifyQuery Q = SQ.getWithInstruction(&Cmp);
     if (Instruction *R = foldCtpopPow2Test(Cmp, II, C, Builder, Q))
       return R;
